import{_ as t,o,c as a,a0 as r}from"./chunks/framework.BjpW4enL.js";const h=JSON.parse('{"title":"PostgreSQL Schema Generation & Best Practices","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/guide/database_practices.md","filePath":"Z_Archive/wiki_legacy/guide/database_practices.md","lastUpdated":1783623176000}'),s={name:"Z_Archive/wiki_legacy/guide/database_practices.md"};function i(n,e,d,c,l,g){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="postgresql-schema-generation-best-practices" tabindex="-1">PostgreSQL Schema Generation &amp; Best Practices <a class="header-anchor" href="#postgresql-schema-generation-best-practices" aria-label="Permalink to &quot;PostgreSQL Schema Generation &amp; Best Practices&quot;">​</a></h1><p>As part of the NEXUS project&#39;s federated and scalable macrostructure, database schemas will dynamically be generated or evolved by LLMs operating via subtasks. To ensure consistency, performance, and maintainability, all LLM-driven schema modifications must strictly adhere to the following PostgreSQL best practices.</p><h2 id="_1-llm-subtask-generation-workflow" tabindex="-1">1. LLM Subtask Generation Workflow <a class="header-anchor" href="#_1-llm-subtask-generation-workflow" aria-label="Permalink to &quot;1. LLM Subtask Generation Workflow&quot;">​</a></h2><p>Instead of monolithic generation, database schemas should be synthesized through bounded subtasks:</p><ul><li><strong>Subtask 1 (Entity Analysis):</strong> Capture entities, access patterns, and scale targets (rows, QPS, retention).</li><li><strong>Subtask 2 (Schema Design):</strong> Choose data types and constraints enforcing invariants. Ensure Normalization (3NF) before any denormalization.</li><li><strong>Subtask 3 (Indexing Strategy):</strong> Add indexes explicitly for access paths actually queried (FKs, frequent filters, join keys).</li><li><strong>Subtask 4 (Validation):</strong> Review migration impact, plan safe rollouts, and generate <code>EXPLAIN</code> validation plans.</li></ul><h2 id="_2-core-constraints-safety" tabindex="-1">2. Core Constraints &amp; Safety <a class="header-anchor" href="#_2-core-constraints-safety" aria-label="Permalink to &quot;2. Core Constraints &amp; Safety&quot;">​</a></h2><ul><li><strong>Primary Keys:</strong> Reference tables MUST use <code>BIGINT GENERATED ALWAYS AS IDENTITY</code>. Use <code>UUID</code> (specifically <code>uuidv7()</code>) only when global uniqueness, opacity, or federated merging is needed.</li><li><strong>Foreign Keys:</strong> PostgreSQL does <strong>not</strong> auto-index FK columns. The LLM MUST explicitly generate <code>CREATE INDEX</code> statements for every FK to avoid slow joins and table locks.</li><li><strong>Nullability &amp; Uniqueness:</strong><ul><li>Add <code>NOT NULL</code> wherever semantically required.</li><li>For unique columns containing nulls, use <code>UNIQUE (...) NULLS NOT DISTINCT</code> (PG15+) to restrict to a single NULL.</li></ul></li><li><strong>Safety:</strong> Avoid destructive DDL on production without a rollback plan. Use transactional DDL (<code>BEGIN; ALTER TABLE...; ROLLBACK;</code>) for testing.</li></ul><h2 id="_3-data-types-lexicon" tabindex="-1">3. Data Types Lexicon <a class="header-anchor" href="#_3-data-types-lexicon" aria-label="Permalink to &quot;3. Data Types Lexicon&quot;">​</a></h2><p>LLM agents must use the following standard mapping:</p><table tabindex="0"><thead><tr><th>Intent</th><th>PostgreSQL Type</th><th>Notes</th></tr></thead><tbody><tr><td>Auto-increment IDs</td><td><code>BIGINT GENERATED ALWAYS AS IDENTITY</code></td><td>Preferred over <code>SERIAL</code>.</td></tr><tr><td>Global IDs</td><td><code>UUID</code></td><td>Use <code>uuidv7()</code> if PG18+, else <code>gen_random_uuid()</code>.</td></tr><tr><td>Timestamps</td><td><code>TIMESTAMPTZ</code></td><td><strong>Never</strong> use <code>TIMESTAMP</code> without time zone.</td></tr><tr><td>Strings</td><td><code>TEXT</code></td><td><strong>Never</strong> use <code>CHAR(n)</code> or <code>VARCHAR(n)</code>. Enforce limits with <code>CHECK (LENGTH(col) &lt;= n)</code>.</td></tr><tr><td>Money</td><td><code>NUMERIC(p, s)</code></td><td><strong>Never</strong> use <code>MONEY</code> or <code>FLOAT</code>.</td></tr><tr><td>Floats</td><td><code>DOUBLE PRECISION</code></td><td>Use <code>NUMERIC</code> for exact decimal arithmetic.</td></tr><tr><td>Booleans</td><td><code>BOOLEAN NOT NULL</code></td><td>Default to NOT NULL unless tri-state is strictly required.</td></tr><tr><td>JSON</td><td><code>JSONB</code></td><td>Index with <code>GIN</code>. Extract scalar search fields to B-tree expression indexes.</td></tr><tr><td>Vectors</td><td><code>vector</code></td><td>Via <code>pgvector</code> for similarity search (Embeddings).</td></tr></tbody></table><h2 id="_4-indexing-partitioning-strategies" tabindex="-1">4. Indexing &amp; Partitioning Strategies <a class="header-anchor" href="#_4-indexing-partitioning-strategies" aria-label="Permalink to &quot;4. Indexing &amp; Partitioning Strategies&quot;">​</a></h2><ul><li><strong>B-tree:</strong> Default for equality, range, and sorting.</li><li><strong>GIN:</strong> Essential for <code>JSONB</code> containment (<code>@&gt;</code>), Arrays (<code>TEXT[]</code>), and Full-Text Search (<code>TSVECTOR</code>).</li><li><strong>GiST:</strong> For ranges (<code>daterange</code>), geometry, and exclusion constraints (<code>EXCLUDE USING gist</code>).</li><li><strong>Partitioning:</strong> Use Declarative Partitioning (<code>RANGE</code> on <code>TIMESTAMPTZ</code> or <code>HASH</code> on <code>user_id</code>) for tables scaling beyond 100M rows. <em>Do not use table inheritance.</em></li></ul><h2 id="_5-safe-schema-evolution-gotchas" tabindex="-1">5. Safe Schema Evolution (Gotchas) <a class="header-anchor" href="#_5-safe-schema-evolution-gotchas" aria-label="Permalink to &quot;5. Safe Schema Evolution (Gotchas)&quot;">​</a></h2><ul><li><strong>Volatile Defaults:</strong> Adding a column with a volatile default (e.g., <code>now()</code>, <code>gen_random_uuid()</code>) will rewrite the entire table and lock it.</li><li><strong>Concurrent Indexes:</strong> Use <code>CREATE INDEX CONCURRENTLY</code> in production to avoid blocking writes (Note: cannot run inside a transaction block).</li><li><strong>Sequences:</strong> Gaps in <code>IDENTITY</code> sequences are normal due to rollbacks. Do not attempt to &quot;fix&quot; or make them consecutive.</li></ul>',14)])])}const m=t(s,[["render",i]]);export{h as __pageData,m as default};
